INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (223, 'Улучшить движения в голенстопном суставе и стопе, порабоать на ее стабилизацией, Носить обувь с широким носком и удобной самой стопе, обратиться к специалисту по вопросу актуальности ношения стелек ', 'https://storage.googleapis.com/fit_review/review/7/223-diagramImage-1741381634205', 60, 'SummaryView-L4', 'SummaryView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/7/223-userImage-1741381592577', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (200, 'Стрелка 6. Нарушена опора стопы. что в свою очередь будет создавать дисбаланс мышц участвующих в стабилизации и площади опоры ', 'https://storage.googleapis.com/fit_review/review/7/200-diagramImage-1741377964359', null, 'FrontView-R4', 'FrontView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/7/200-userImage-1741377950000', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (161, 'Insert your description hereаумаум', 'https://storage.googleapis.com/fit_review/review/6/161-diagramImage-1740853903700', null, 'FrontView-L1', 'FrontView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/6/161-userImage-1740853899096', 6);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (343, 'Стрелка 5 Вид стопы и голени с стороны неплохой, как и ранее упоминалось имеется арка стопы, пространство между пальцев. ', 'https://storage.googleapis.com/fit_review/review/11/343-diagramImage-1744290507097', null, 'SideView-L4', 'SideView', 'Left View Feet', 'https://storage.googleapis.com/fit_review/review/11/343-userImage-1744290913980', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (218, 'Обратиться к специалисту( кинезиологу или остеопату) разгрузить шейноворатниковую зону скоорректировать симетрию, восстановить плечелопаточный ритм засчет упражнений. Тренировки, динамический стретчинг, пилатес, тренировки на дыхание, силовой тренинг, функциональный тренинг с свободным весом ', 'https://storage.googleapis.com/fit_review/review/7/218-diagramImage-1741381641437', 40, 'SummaryView-R1', 'SummaryView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/7/218-userImage-1741381672680', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (216, 'Стрелка 8. Голеностопный сустав. Похожая ситуация с левой стороной ', 'https://storage.googleapis.com/fit_review/review/7/216-diagramImage-1741380900425', null, 'SideView-R4', 'SideView', 'Right View Feet', 'https://storage.googleapis.com/fit_review/review/7/216-userImage-1741380835177', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (360, 'Левая сторона стопы и голеностопного сустава выглядит лучше. Арка стопы больше расположена к нейтральной позиции, как и голеностопный сустав, но форма голени также развернута к наруже. ', 'https://storage.googleapis.com/fit_review/review/12/360-diagramImage-1746095622380', null, 'FrontView-R4', 'FrontView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/12/360-userImage-1746095330246', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (197, 'Стрелка 5. Бедро развернуто наружу( может быть вызвано, нестабильной работы ягодичных мышц и кора , изменением положение таза, нарушением работы мышц участвующие в работе стопе. Изменение паттерна шага в совокупности это создает мышечный дисбаланс, адаптации и изменение положение конечностей ', 'https://storage.googleapis.com/fit_review/review/7/197-diagramImage-1741377824610', null, 'FrontView-L3', 'FrontView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/7/197-userImage-1741377796783', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (318, 'Тазобедренный регион. Ранее описанные рекомендации вы можете изучить еще раз слева. Важно обратить внимание. то поможет улучшить функционал таза ', 'https://storage.googleapis.com/fit_review/review/10/318-diagramImage-1742828503985', 65, 'SummaryView-R3', 'SummaryView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/10/318-userImage-1742828437925', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (193, 'Стрелка 0. Смещение подбородка влево. Предполагает дисбаланс работы мышц шейного отдела позвонка и черепа Стрелка 1. Расположение надплечий ассимитрично, причины предположительны в левой стороне. Левое надплечье выше, положение черепа развернуто влево, плечо менее выкуплено, есть предподожение о наличии диссфункций мышц в плече лопаточном регионе ', 'https://storage.googleapis.com/fit_review/review/7/193-diagramImage-1741377728508', null, 'FrontView-L1', 'FrontView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/7/193-userImage-1741377714493', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (194, 'Стрелка 1. Левое надплечье выше правого. Предпологает гипертонус верхней порции трапецивидной из-за нестабильной работы дельтовидных мышц плеча. Также может быть вызвана из-за повсевдневных привычек( неправильное сидение, привычные  позы на одну сторону , ношение рюзказа на одну сторону, стрессы, дыхание ) Стрелка 4.1.П лечо ( дельтовидная ) выглядит менее выкуплой чем правое, что в свою очередь может выразит слабость работы мышц, и перегрузкой мышц находящихся рядом ', 'https://storage.googleapis.com/fit_review/review/7/194-diagramImage-1741377880991', null, 'FrontView-R1', 'FrontView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/7/194-userImage-1741377861424', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (199, '', 'https://storage.googleapis.com/fit_review/review/7/199-diagramImage-1741377848171', null, 'FrontView-L4', 'FrontView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/7/199-userImage-1741377837380', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (198, 'Стрелка 5. Бедро развернуто наружу( может быть вызвано, нестабильной работы ягодичных мышц и кора , изменением положение таза, нарушением работы мышц участвующие в работе стопе. Изменение паттерна шага в совокупности это создает мышечный дисбаланс, адаптации и изменение положение конечностей ', 'https://storage.googleapis.com/fit_review/review/7/198-diagramImage-1741377939583', null, 'FrontView-R3', 'FrontView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/7/198-userImage-1741377922770', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (338, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце и других мышц разгибателей корпуса .', 'https://storage.googleapis.com/fit_review/review/11/338-diagramImage-1744290484389', null, 'SideView-R1', 'SideView', 'Right View Upper Body', 'https://storage.googleapis.com/fit_review/review/11/338-userImage-1744290889852', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (224, 'Улучшить движения в голенстопном суставе и стопе, порабоать на ее стабилизацией, Носить обувь с широким носком и удобной самой стопе, обратиться к специалисту по вопросу актуальности ношения стелек ', 'https://storage.googleapis.com/fit_review/review/7/224-diagramImage-1741381659905', 65, 'SummaryView-R4', 'SummaryView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/7/224-userImage-1741381690206', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (314, 'Шейный регион. все вышеупомянутые рекомендации были предоставлены в заметке правой стороны. Важно обратить на них внимание и приступить к взаимодействию с ними ', 'https://storage.googleapis.com/fit_review/review/10/314-diagramImage-1742828479410', 60, 'SummaryView-R1', 'SummaryView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/10/314-userImage-1742828405025', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (312, 'Тело наклонено вперед. Рекомендуется обратить внимание на работу таза и мышц брюшного пресса для стабилизации тела в вертикальном положении.', 'https://storage.googleapis.com/fit_review/review/10/312-diagramImage-1742768642912', null, 'SideView-R4', 'SideView', 'Right View Feet', 'https://storage.googleapis.com/fit_review/review/10/312-userImage-1742768585160', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (320, 'Стопа. Ранее описанные рекомендации вы можете изучить еще раз слева. Важно обратить внимание.  Это поможет улучшить Общий функционал стопы ', 'https://storage.googleapis.com/fit_review/review/10/320-diagramImage-1742828517175', 45, 'SummaryView-R4', 'SummaryView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/10/320-userImage-1742828449626', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (210, 'Стрелка 1. Короткие и длинные сгибатели и разгибатели мышцы шеи в дисбалансе. Наблюдается смещение черепа Стрелка 2. Мышцы ротаторы плеча и региона плеча . Аналагичная ситуация что и слевой стороной, с левой стороны ярче выражено. можно обратить внимание на длину рук, левая выше, а значит дельтовидная не работает', 'https://storage.googleapis.com/fit_review/review/7/210-diagramImage-1741380885887', null, 'SideView-R1', 'SideView', 'Right View Upper Body', 'https://storage.googleapis.com/fit_review/review/7/210-userImage-1741380820865', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (382, 'Бедро. Восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/12/382-diagramImage-1746095653047', 60, 'SummaryView-R3', 'SummaryView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/12/382-userImage-1746175851703', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (212, 'Стрелка 3 . Смещение лопатки в сторону. Причиной этого может быть дисбаланс работы мышц  участвющие в ее стабилизации и движении, дисбаланс работы мышц спереди и сзади корпуса, нарушение работы мышц участвиющие в дыхании, изменение осанки Стрелка 4 . Расскрытие ребра, наполненость живота. Возможные причины-  слабые и некорректно работающие мышцы кора  - стабилизация, распределение внутребрюшного давления) также есть вопросы по жкт. Также изменение положения таза может влиять на изменение верхнего региона Стрелка 5. Поясничный регион перенапряжен, потенциальные причины( дисбаланс работы мышц кора и таза, смещение таза и грудного отдела позвонка с нейтрали )  ', 'https://storage.googleapis.com/fit_review/review/7/212-diagramImage-1741380890736', null, 'SideView-R2', 'SideView', 'Right View Core', 'https://storage.googleapis.com/fit_review/review/7/212-userImage-1741380826274', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (217, 'Особое внимание уделить левой стороне шейноворотниковой зоны, восстановить симметрию с помощью специалистов, разгрузить перегруженность мышц, восстановить движение шейного и грудного региона позвонков, уделить вниматение плече лопаточному региону тоже. ', 'https://storage.googleapis.com/fit_review/review/7/217-diagramImage-1741381614603', 60, 'SummaryView-L1', 'SummaryView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/7/217-userImage-1741381580635', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (265, 'Наблюдается мышечный дисбаланс в шейно-плечелопаточной области, особенно справа. Нестабильность мышц плеча и лопатки может привести к нарушению функции трапециевидной мышцы, влияя на стабилизацию и движение шейного отдела.', 'https://storage.googleapis.com/fit_review/review/9/265-diagramImage-1744227329096', null, 'BackView-L1', 'BackView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/9/265-userImage-1744227427815', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (292, 'Стрелка 3: Левый сосок выше правого, что может указывать на фасциальное укорочение или наличие триггерных точек. Это предполагает дисбаланс в работе грудных мышц, вероятно, с пониженной активностью левой стороны.', 'https://storage.googleapis.com/fit_review/review/10/292-diagramImage-1742768254663', null, 'FrontView-R2', 'FrontView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/10/292-userImage-1742768167032', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (311, 'Тело наклонено вперед. Рекомендуется обратить внимание на работу таза и мышц брюшного пресса для стабилизации тела в вертикальном положении.', 'https://storage.googleapis.com/fit_review/review/10/311-diagramImage-1742768638220', null, 'SideView-L4', 'SideView', 'Left View Feet', 'https://storage.googleapis.com/fit_review/review/10/311-userImage-1742768579774', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (304, 'Стрелка 5: Касание внутренней стороны стопы пола указывает на дисбаланс мышц, отвечающих за её стабилизацию и движение пальцев. Это снижает устойчивость стопы, уменьшает площадь опоры и изменяет биомеханику голеностопного сустава. В результате внутренняя головка икроножной мышцы может спазмироваться, смещая пяточную кость.', 'https://storage.googleapis.com/fit_review/review/10/304-diagramImage-1742768445603', null, 'BackView-R4', 'BackView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/10/304-userImage-1742768380044', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (305, 'Незначительный сдвиг шеи вперед. Аналогичный вид и с правой стороны. Первоисточником сдвига шея могут быть коррекции структуры позвонка, таза , стоп.  ', 'https://storage.googleapis.com/fit_review/review/10/305-diagramImage-1742768600176', null, 'SideView-L1', 'SideView', 'Left View Upper Body', 'https://storage.googleapis.com/fit_review/review/10/305-userImage-1742768542749', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (302, 'Правильное положение бедер и отсутствие складок в пояснице указывают на нейтральное расположение бедра и таза. Однако ограниченная площадь опоры стопы и сниженная подвижность голеностопного сустава могут привести к мышечному дисбалансу в бедрах, тазу и выше.', 'https://storage.googleapis.com/fit_review/review/10/302-diagramImage-1742768433736', null, 'BackView-R3', 'BackView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/10/302-userImage-1742768363631', 10);
