INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (195, 'Стрелка 2 Расположение левого соска ассиметрично правому. Обратить внимание на заметку 2 левая сторона. Стрелка4  Рука развернута внутрь, Предположение, нестабильность работы мышц участвющих в работе лопатки, плеча( Ромбовидные, передняя зубчатая м. Ротаторы плеча, малая грудная мышца) Причины, нарушение дыхания, закрытая привычная сидячая поза, перегруз передней мышечной цепи в работе тренировках ) . Стрелка 3 .  Пупок немного стянут в сторону, есть вопросы к работе кишечника и в целом работы жкт, раьоты кора в совокупности ', 'https://storage.googleapis.com/fit_review/review/7/195-diagramImage-1741377771594', null, 'FrontView-L2', 'FrontView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/7/195-userImage-1741377757928', 7);
