INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (288, 'Стопа. Рекомендация обратиться к филологу по проверке состояния вен, купить компрессионные носки по рекомендации врача. выполнять упражнения на улучшения общего тонуса мышц стопы, ходить босиком чаще, носить обувь с широким носком и равномерно подошвой,  ', 'https://storage.googleapis.com/fit_review/review/9/288-diagramImage-1744225877651', 60, 'SummaryView-R4', 'SummaryView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/9/288-userImage-1744225829431', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (273, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце и других мышц разгибателей корпуса .', 'https://storage.googleapis.com/fit_review/review/9/273-diagramImage-1743507627427', null, 'SideView-L1', 'SideView', 'Left View Upper Body', 'https://storage.googleapis.com/fit_review/review/9/273-userImage-1743507552407', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (308, 'Стрелка 2: Рука повернута к корпусу, что подтверждается видом сбоку. Смотрите лицевой и задний вид тела 
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (286, 'Бедро. Перегрузка приводящих мышц бедра и слабость остальных. Это нарушает баланс, влияет на тазобедренный сустав и движение. Нужно восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/9/286-diagramImage-1744225868487', 50, 'SummaryView-R3', 'SummaryView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/9/286-userImage-1744225818368', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (280, 'Стрелка 5: Чуть менее выражена пронация стопы, но все же есть, возможно что распределение веса будет больше на левую сторону из-за больших количества дисфункций в нижней конечности ', 'https://storage.googleapis.com/fit_review/review/9/280-diagramImage-1743507669827', null, 'SideView-R4', 'SideView', 'Right View Feet', 'https://storage.googleapis.com/fit_review/review/9/280-userImage-1743507599629', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (264, 'Стрелка 7 и 6 При касании внутренней стороны стопы пола наблюдается дисбаланс мышц, стабилизирующих стопу и голеностопный сустав. Это снижает стабильность стопы, уменьшает площадь опоры и изменяет движения голеностопного сустава и разворачивает голень кнаружи от центра , что может привести к дисфункциям в тазобедренном и поясничном отделах.', 'https://storage.googleapis.com/fit_review/review/9/264-diagramImage-1744205945160', null, 'FrontView-R4', 'FrontView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/9/264-userImage-1744206251974', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (196, 'Стрелка 2. Расположение соска ( выше правого и смещено вправо) предположение ( фасциальное укорочение или триггерные точки, может быть вместе ) - выражается перегрузкой мышц расположеных рядом или самой мышцы,что в свою очередь мышченое волокно и фасция изменяется в своей структуре, становится тверже и менее эластичнее. причины: Перегруженность работы мышц окружающие плече-лопаточный регион, мышц участвующих при дыхании. Возможно потенциальная причина в нетсабильной работе дельтовидной мышце плеча.  Стрелка 4. Рука развернута внутрь, Предположение, нестабильность работы мышц участвющих в работе лопатки, плеча( Ромбовидные, передняя зубчатая м. Ротаторы плеча, малая грудная мышца) Причины, нарушение дыхания, закрытая привычная сидячая поза, перегруз передней мышечной цепи в работе тренировках )  Стрелка 3. Пупок немного стянут в сторону, есть вопросы к работе кишечника и в целом работы жкт, раьоты кора в совокупности ', 'https://storage.googleapis.com/fit_review/review/7/196-diagramImage-1741377907434', null, 'FrontView-R2', 'FrontView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/7/196-userImage-1741377891915', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (201, 'Стрелка 3. Смещение лопатки в сторону. Причиной этого может быть дисбаланс работы мышц  участвющие в ее стабилизации и движении, дисбаланс работы мышц спереди и сзади корпуса, нарушение работы мышц участвиющие в дыхании, изменение осанки, ', 'https://storage.googleapis.com/fit_review/review/7/201-diagramImage-1741383163826', null, 'BackView-L1', 'BackView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/7/201-userImage-1741383131591', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (269, 'Наблюдается ограниченная площадь опоры стопы и сниженная подвижность голеностопного сустава могут привести к мышечному дисбалансу в бедрах и тазобедренном суставе. Также наблюдается смещение таза вправо что будет создавать дополнительный мышечный гипертонус вправо ', 'https://storage.googleapis.com/fit_review/review/9/269-diagramImage-1744227357479', null, 'BackView-L3', 'BackView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/9/269-userImage-1744227558522', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (203, 'Стрелка 4. Мышцы ротаторы плеча и региона плеча . Наблюдается как руки развернуты вовнутрь и кпереди Предположение о дисбалансе работе мышц окружающие плечевой регион, лопатки, грудной регион(спереди и сзади) Стрелка 6. Поясничный регион. Ориентируясь по центральной линии виднеется прогиб в поясничном регионе. Одной из причин может быть слабость мышц кора и ягодиц, что в совокупности могут  создать дисбаланс ', 'https://storage.googleapis.com/fit_review/review/7/203-diagramImage-1741383166371', null, 'BackView-L2', 'BackView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/7/203-userImage-1741383136372', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (207, 'Стрелка 9.Стопа и голеностопный сустав не стабильны.Исходя из опоры, ноги развернуты в разные стороны. Это будет создавать некорректное сгибание стопы во время шага и нарушение площади опоры и самой опоры. Это также будет сказываться на дисбалансе работ мышц участвующие в работе стопы', 'https://storage.googleapis.com/fit_review/review/7/207-diagramImage-1741383170335', null, 'BackView-L4', 'BackView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/7/207-userImage-1741383142123', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (202, 'Стрелка 2 .Левое надплечье выше правого. Предпологает гипертонус верхней порции трапецивидной из-за нестабильной работы дельтовидных мышц плеча. Также заметна более выкуплая форма по сравнению с правой стороной. Подобный дисбаланс может вызвать ряд мышечный диссфункций, ассиметрий и другий факторов в теле  Стрелка 3. Смещение лопатки в сторону. Причиной этого может быть дисбаланс работы мышц  участвющие в ее стабилизации и движении, дисбаланс работы мышц спереди и сзади корпуса, нарушение работы мышц участвиющие в дыхании, изменение осанки, .', 'https://storage.googleapis.com/fit_review/review/7/202-diagramImage-1741383173498', null, 'BackView-R1', 'BackView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/7/202-userImage-1741383145378', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (206, 'Стрелка 7 . Наблюдается разворот бедра в сторону. Работа ягодичных мышц изходя из этого может работать нестабильно, а ротатры бедра ( что под ягодичными) могут быть наоборот в гипертонусе, что в свою очередь разворачивать бедро к наруже.  Стрелка 8 . Бедро развернуто наружу что в свою очередь будет создавать дисбаланс в работе мышц бедра. Мышцы бедра ближе к наруже будут в гипертонусе, те что ближе к внутренней в гипотонусе ', 'https://storage.googleapis.com/fit_review/review/7/206-diagramImage-1741383178067', null, 'BackView-R3', 'BackView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/7/206-userImage-1741383155598', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (209, 'Стрелка 1. Короткие и длинные сгибатели и разгибатели мышцы шеи в дисбалансе. Наблюдается смещение черепа  Стрелка 2 .Мышцы ротаторы плеча и региона плеча . Наблюдается как руки развернуты вовнутрь и кпереди Предположение о дисбалансе работе мышц окружающие плечевой регион, лопатки, грудной регион(спереди и сзади) ', 'https://storage.googleapis.com/fit_review/review/7/209-diagramImage-1741380856685', null, 'SideView-L1', 'SideView', 'Left View Upper Body', 'https://storage.googleapis.com/fit_review/review/7/209-userImage-1741380816429', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (205, 'Стрелка 7. Наблюдается разворот бедра в сторону. Работа ягодичных мышц изходя из этого может работать нестабильно, а ротатры бедра ( что под ягодичными) могут быть наоборот в гипертонусе, что в свою очередь разворачивать бедро к наруже. Стрелка 8 . Бедро развернуто наружу что в свою очередь будет создавать дисбаланс в работе мышц бедра. Мышцы бедра ближе к наруже будут в гипертонусе, те что ближе к внутренней в гипотонусе  ', 'https://storage.googleapis.com/fit_review/review/7/205-diagramImage-1741383168400', null, 'BackView-L3', 'BackView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/7/205-userImage-1741383139014', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (284, 'Туловище. Ранее описанные рекомендации вы можете изучить еще раз слева. Важно обратить внимание.  Это ядро человека где проходят все важные процессы для поддержания жизнедеятельности в особенности структура тела ', 'https://storage.googleapis.com/fit_review/review/9/284-diagramImage-1744225855474', 50, 'SummaryView-R2', 'SummaryView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/9/284-userImage-1744225809238', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (204, 'Стрелка 4. Мышцы ротаторы плеча и региона плеча . Наблюдается как руки развернуты вовнутрь и кпереди Предположение о дисбалансе работе мышц окружающие плечевой регион, лопатки, грудной регион(спереди и сзади) Стрелка 5 . Левый локоть выше распологается чем правый, предпологаемая  причина- нестабильная работа дельтовидных мышц плеча и перегруженность верхней порции трапецивидное что в свое очередь вместо дельтовидной держит руку и поднимает ее.  Стрелка 6.  Поясничный регион. Ориентируясь по центральной линии виднеется прогиб в поясничном регионе. Одной из причин может быть слабость мышц кора и ягодиц, что в совокупности могут  создать дисбаланс', 'https://storage.googleapis.com/fit_review/review/7/204-diagramImage-1741383175600', null, 'BackView-R2', 'BackView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/7/204-userImage-1741383148943', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (208, 'Стрелка 9. Стопа и голеностопный сустав не стабильны.Исходя из опоры, ноги развернуты в разные стороны. Это будет создавать некорректное сгибание стопы во время шага и нарушение площади опоры и самой опоры. Это также будет сказываться на дисбалансе работ мышц участвующие в работе стопы', 'https://storage.googleapis.com/fit_review/review/7/208-diagramImage-1741383179820', null, 'BackView-R4', 'BackView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/7/208-userImage-1741383158005', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (214, 'Стрелка 6 . Наблюдается наклон таза вперед Аналогичная ситуация что и слевой стороной  Стрелка 7 .  Дисбаланс в мышцах бедра. Аналогичая ситуация что и с левой стороной ', 'https://storage.googleapis.com/fit_review/review/7/214-diagramImage-1741380895177', null, 'SideView-R3', 'SideView', 'Right View Hips', 'https://storage.googleapis.com/fit_review/review/7/214-userImage-1741380830742', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (364, 'Стрелка 3 Из-за сдвига таза наблюдается асимметрия корпуса, потенциальные причины описаны под стрелкой 2 ', 'https://storage.googleapis.com/fit_review/review/12/364-diagramImage-1746095837664', null, 'BackView-R2', 'BackView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/12/364-userImage-1746173883055', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (278, 'Стрелка 4: Смещение таза вперёд может быть вызвано слабостью задней группы мышц: ягодичных, задней поверхности бедра, икроножных и мышц стопы. Основные причины включают сидячий образ жизни, неправильное распределение веса и изменения в функционировании нижних конечностей.', 'https://storage.googleapis.com/fit_review/review/9/278-diagramImage-1743507658688', null, 'SideView-R3', 'SideView', 'Right View Hips', 'https://storage.googleapis.com/fit_review/review/9/278-userImage-1743507587401', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (277, 'Стрелка 4: Смещение таза вперёд может быть вызвано слабостью задней группы мышц: ягодичных, задней поверхности бедра, икроножных и мышц стопы. Основные причины включают сидячий образ жизни, неправильное распределение веса и изменения в функционировании нижних конечностей.', 'https://storage.googleapis.com/fit_review/review/9/277-diagramImage-1743507652425', null, 'SideView-L3', 'SideView', 'Left View Hips', 'https://storage.googleapis.com/fit_review/review/9/277-userImage-1743507581060', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (211, 'Стрелка 3. Смещение лопатки в сторону. Причиной этого может быть дисбаланс работы мышц  участвющие в ее стабилизации и движении, дисбаланс работы мышц спереди и сзади корпуса, нарушение работы мышц участвиющие в дыхании, изменение осанки Стрелка 4. Расскрытие ребра, наполненость живота. Возможные причины-  слабые и некорректно работающие мышцы кора  - стабилизация, распределение внутребрюшного давления) также есть вопросы по жкт. Также изменение положения таза может влиять на изменение верхнего региона.  Стрелка 5 . Поясничный регион перенапряжен, потенциальные причины( дисбаланс работы мышц кора и таза, смещение таза и грудного отдела позвонка с нейтрали ) ', 'https://storage.googleapis.com/fit_review/review/7/211-diagramImage-1741380863011', null, 'SideView-L2', 'SideView', 'Left View Core', 'https://storage.googleapis.com/fit_review/review/7/211-userImage-1741380812372', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (213, 'Стрелка 6 . Наблюдается наклон таза вперед. Мышцы бедер в дисбалансе, таз фактические сидит на заднем бедре. Ягодичные мышцы не стабильны Стрелка 7. Дисбаланс в мышцах бедра. Задняя поверхность бедра  в гипертонсуе, можно обратить внимание что таз фактически сидит на заднем бедре, вероятная причина находится в  нестабильной работе голеностопного  суства ( недостаточно сгибание ) и стопы ', 'https://storage.googleapis.com/fit_review/review/7/213-diagramImage-1741380869762', null, 'SideView-L3', 'SideView', 'Left View Hips', 'https://storage.googleapis.com/fit_review/review/7/213-userImage-1741380798722', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (215, 'Стрелка 8 .Голеностопый сустав и стопа.  Изходя из положения таза, есть предположение что голеностопынй сустав ограничен в сгибании стопы, это в свою очередь может создать некорректную работу мышц верхних регионов что в свою очередь тело может адаптироваться и меняться в структуре ', 'https://storage.googleapis.com/fit_review/review/7/215-diagramImage-1741380876340', null, 'SideView-L4', 'SideView', 'Left View Feet', 'https://storage.googleapis.com/fit_review/review/7/215-userImage-1741380806542', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (219, 'Улучшить мобильность грудного и шейного региона позвоночника, разгрузить передню мышечную цепь( корпус ) а привести в тонус заднюю.  добавить тренировки на дыхание, тренировки на плече лопаточный регион, на кор. Обратиться к специалисту кто делает фисцеральный массаж, проверить общее состояние органов', 'https://storage.googleapis.com/fit_review/review/7/219-diagramImage-1741381621501', 60, 'SummaryView-L2', 'SummaryView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/7/219-userImage-1741381585267', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (221, 'Улучшить функционал тазобедренного региона, восстановить мышечный тонус мышц участвующие движении тазобедреноого региона и ног. Восстановитеьный процедуры, массаж, мфр, гимнастика. Обязательно уделять внимание и стопе, так как возможно это первоисточник в дисфукнциаях таза ', 'https://storage.googleapis.com/fit_review/review/7/221-diagramImage-1741381627538', 58, 'SummaryView-L3', 'SummaryView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/7/221-userImage-1741381589071', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (220, 'Улучшить мобильность грудного и шейного региона позвоночника, разгрузить передню мышечную цепь( корпус ) а привести в тонус заднюю.  добавить тренировки на дыхание, тренировки на плече лопаточный регион, на кор. Обратиться к специалисту кто делает фисцеральный массаж, проверить общее состояние органов', 'https://storage.googleapis.com/fit_review/review/7/220-diagramImage-1741381648579', 40, 'SummaryView-R2', 'SummaryView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/7/220-userImage-1741381679267', 7);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (222, 'Улучшить функционал тазобедренного региона, восстановить мышечный тонус мышц участвующие движении тазобедреноого региона и ног. Восстановитеьный процедуры, массаж, мфр, гимнастика. Обязательно уделять внимание и стопе, так как возможно это первоисточник в дисфукнциаях таза ', 'https://storage.googleapis.com/fit_review/review/7/222-diagramImage-1741381654536', 58, 'SummaryView-R3', 'SummaryView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/7/222-userImage-1741381685193', 7);
