INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (243, null, null, null, 'SideView-L2', 'SideView', 'Left View Core', null, 8);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (279, 'Стрелка5: Пронация стопы, её заваливание внутрь, при котором внутренняя часть стопы почти полностью касается пола. Это может быть вызвано слабостью мышц стопы и голени, что приводит к неравномерному распределению веса и повышенной нагрузке на коленный сустав. Со временем это может привести к плоскостопию, деформации стопы и болям в суставах. ', 'https://storage.googleapis.com/fit_review/review/9/279-diagramImage-1743507665412', null, 'SideView-L4', 'SideView', 'Left View Feet', 'https://storage.googleapis.com/fit_review/review/9/279-userImage-1743507594617', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (268, 'Стрелка 2. Правая лопатка выше левой. Потенциальной причиной может быть гипотонус дельтовидной мышцы и далее полученный мышечный дисбаланс региона плеча и лопатки. возможно привычное сидение на правую сторону ношение рюкзака вызвали причину коррекции туловища. Стрелка 3. Смещение туловища в сторону. Наблюдается асимметрия левой и правой сторон корпуса, мышечный дисбаланс мышц разгибателей корпуса и сгибателей корпуса. Движение позвоночника будет ограничено больше вправо ', 'https://storage.googleapis.com/fit_review/review/9/268-diagramImage-1744227348857', null, 'BackView-R2', 'BackView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/9/268-userImage-1744227550637', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (260, 'Стрелка 4 По левой  стороне наблюдается вытяжение  тканей и завал корпуса вправо. Может быть вызвано привычном сидячим положением корпуса, стоя при опоре на правую ногу, ношение тяжестей на одну сторону. Наблюдается мышечный дисбаланс живота (косых мышц, межреберных мышц, диафрагмы и разгибателей мышц спины) вдох будет легче выполняться влево чем вправо и любые движение позвонка тоже лучше чем вправо. ', 'https://storage.googleapis.com/fit_review/review/9/260-diagramImage-1744205919783', null, 'FrontView-R2', 'FrontView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/9/260-userImage-1744206119260', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (266, 'Стрелка 1. Гипотонус дельтовидной мышцы, возможно из-за фасциального укорочения, триггерных точек или незначительной травмы. В результате стабилизация руки осуществляется ротаторами плеча и верхней частью трапециевидной мышцы, что может привести к дисфункциям в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/9/266-diagramImage-1744227335943', null, 'BackView-R1', 'BackView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/9/266-userImage-1744227434071', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (257, 'Стрелка 1. Ключица направлена вниз по дуге, это будет влиять на форму, объемность вдоха в грудной клетки, выпячивание лопаток( торчащие сзади ) , уплощение грудной клетки. Также вероятно защемление нервных окончаний и онемение рук при держании над головой. Стрелка 2. Правое надплечье выше левого.  Из-за различной длины рук дельтовидная мышца может быть в гипотонусе, что приводит к перегрузке ротаторов плеча и верхней части трапециевидной мышцы, вызывая дисфункции в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/9/257-diagramImage-1744205901086', null, 'FrontView-L1', 'FrontView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/9/257-userImage-1744206104997', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (271, 'Стрелка 5. Наблюдается варикоз. возможно приобретенный либо врожденный. Циркуляция крови через таз вверх и обратно вниз будет нарушаться. При изменение структуры стопы это  будет усиливать застой крови и ухудшать  состояние. Важно восстановить баланс и работу стопы.', 'https://storage.googleapis.com/fit_review/review/9/271-diagramImage-1744227371707', null, 'BackView-L4', 'BackView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/9/271-userImage-1744227569980', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (267, 'Стрелка 4. Наблюдается смещение таза вправо. Опора нарушена наблюдается мышечный дисбаланс в зоне таза(ягодичные все три мышцы )  и бедер (всех групп мышц ) . Это будет влиять на расположение корпуса и дальнейшей коррекции мышечного баланса ', 'https://storage.googleapis.com/fit_review/review/9/267-diagramImage-1744227344485', null, 'BackView-L2', 'BackView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/9/267-userImage-1744227537108', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (287, 'Стопа. Обратиться  специалисту по стелькам. Далее выполнять упражнения на улучшение общего тонуса мышц стопы, ходить босиком чаще, носить обувь с широким носком и равномерно подошвой. ', 'https://storage.googleapis.com/fit_review/review/9/287-diagramImage-1744225872606', 60, 'SummaryView-L4', 'SummaryView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/9/287-userImage-1744225826491', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (296, 'Стрелка 6: При касании внутренней стороны стопы пола наблюдается дисбаланс мышц, стабилизирующих стопу и голеностопный сустав. Это снижает стабильность стопы, уменьшает площадь опоры и изменяет движения голеностопного сустава, что может привести к дисфункциям в тазобедренном и поясничном отделах.', 'https://storage.googleapis.com/fit_review/review/10/296-diagramImage-1742768285608', null, 'FrontView-R4', 'FrontView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/10/296-userImage-1742768189835', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (295, 'Стрелка 6. Cтопа и голеностопный сустав.  Внутрення сторона стопы касается пола, это говорит от том что есть дисбаланс в мышцах участвующих за стабилизацию стопы,  движение пальцев стопы, мышц голени. По этой причине, стопа становится менее стабильной, теряет площадь опоры, точки опоры далее изменяется движения  голеностопного сустава. Сгибание и разгибание в голеностопном суставе будет происходить с ограниченностью и дальнейшем создавать дисфункции в верхний регионах - таз, грудной отдел ', 'https://storage.googleapis.com/fit_review/review/10/295-diagramImage-1742768278950', null, 'FrontView-L4', 'FrontView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/10/295-userImage-1742768195074', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (289, 'Стрелка 1: Наклон головы вправо с поворотом подбородка влево может свидетельствовать о верхнем перекрёстном синдроме, где наблюдается дисбаланс между напряжёнными и слабыми мышцами, влияющий на положение головы и шеи.  ￼
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (290, 'Наблюдается дисбаланс мышц в шейном и плечево-лопаточном отделах, особенно с правой стороны. Эта нестабильность может приводить к нарушению работы мышц шеи и плеча.', 'https://storage.googleapis.com/fit_review/review/10/290-diagramImage-1742768239768', null, 'FrontView-R1', 'FrontView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/10/290-userImage-1742768147996', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (259, 'Стрелка 3.  По правой стороне наблюдается сокращение тканей и завал корпуса вправо. Может быть вызвано привычном сидячим положением корпуса, стоя при опоре на правую ногу, ношение тяжестей на одну сторону. Наблюдается мышечный дисбаланс живота (косых мышц, межреберных мышц, диафрагмы и разгибателей мышц спины) ', 'https://storage.googleapis.com/fit_review/review/9/259-diagramImage-1744205913879', null, 'FrontView-L2', 'FrontView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/9/259-userImage-1744206115274', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (272, 'Стрелка 5. Такая же  ситуация с варикозом с правой стороны . Стрелка 6 Касание внутренней стороны стопы пола указывает на дисбаланс мышц, отвечающих за её стабилизацию и движение пальцев. Это снижает устойчивость стопы, уменьшает площадь опоры и изменяет биомеханику голеностопного сустава. В результате внутренняя головка икроножной мышцы может спазмироваться, смещая пяточную кость.', 'https://storage.googleapis.com/fit_review/review/9/272-diagramImage-1744227378516', null, 'BackView-R4', 'BackView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/9/272-userImage-1744227573394', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (346, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/11/346-diagramImage-1744288566958', 55, 'SummaryView-R1', 'SummaryView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/11/346-userImage-1744288419185', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (350, 'Бедро. Восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/11/350-diagramImage-1744288583086', 65, 'SummaryView-R3', 'SummaryView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/11/350-userImage-1744288438907', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (352, 'Стопа. Выполнять упражнения на улучшение общего тонуса мышц стопы, приоритет тренировок на стабилизацию стопы и улучшение её площади опоры. Ходить босиком чаще, носить обувь с широким носком и равномерной подошвой. ', 'https://storage.googleapis.com/fit_review/review/11/352-diagramImage-1744288591932', 60, 'SummaryView-R4', 'SummaryView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/11/352-userImage-1744288448611', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (294, 'Стрелка 5: Ограничение подвижности стопы и голеностопного сустава изменяет работу мышц бедра и таза, что может привести к смещению тазобедренного и коленного суставов. Нагрузки на внутреннюю поверхность бедра увеличиваются, что может вызвать нестабильность коленного сустава.', 'https://storage.googleapis.com/fit_review/review/10/294-diagramImage-1742768270010', null, 'FrontView-R3', 'FrontView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/10/294-userImage-1742768177088', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (300, 'Стрелки 3 и 4: Правый локоть слегка отстоит от корпуса, а рука повернута внутрь. Возможная причина — дисбаланс мышц-вращателей плеча и окружающих лопатку. Это влияет на положение предплечья и ладони, а также на функционирование мышц всей руки. В норме ладони должны быть обращены друг к другу.', 'https://storage.googleapis.com/fit_review/review/10/300-diagramImage-1742768416678', null, 'BackView-R2', 'BackView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/10/300-userImage-1742768340031', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (285, 'Бедро. Перегрузка приводящих мышц бедра и слабость остальных. Это нарушает баланс, влияет на тазобедренный сустав и движение. Нужно восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/9/285-diagramImage-1744225864718', 50, 'SummaryView-L3', 'SummaryView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/9/285-userImage-1744225814744', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (301, 'Правильное положение бедер и отсутствие складок в пояснице указывают на нейтральное расположение бедра и таза. Однако ограниченная площадь опоры стопы и сниженная подвижность голеностопного сустава могут привести к мышечному дисбалансу в бедрах, тазу и выше.', 'https://storage.googleapis.com/fit_review/review/10/301-diagramImage-1742768426878', null, 'BackView-L3', 'BackView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/10/301-userImage-1742768345616', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (293, 'Стрелка 5: Ограничение подвижности стопы и голеностопного сустава изменяет работу мышц бедра и таза, что может привести к смещению тазобедренного и коленного суставов. Нагрузки на внутреннюю поверхность бедра увеличиваются, что может вызвать нестабильность коленного сустава.', 'https://storage.googleapis.com/fit_review/review/10/293-diagramImage-1742768263121', null, 'FrontView-L3', 'FrontView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/10/293-userImage-1742768182751', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (303, 'Стрелка 5: Касание внутренней стороны стопы пола указывает на дисбаланс мышц, отвечающих за её стабилизацию и движение пальцев. Это снижает устойчивость стопы, уменьшает площадь опоры и изменяет биомеханику голеностопного сустава. В результате внутренняя головка икроножной мышцы может спазмироваться, смещая пяточную кость.', 'https://storage.googleapis.com/fit_review/review/10/303-diagramImage-1742768441081', null, 'BackView-L4', 'BackView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/10/303-userImage-1742768374461', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (282, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/9/282-diagramImage-1744225844463', 45, 'SummaryView-R1', 'SummaryView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/9/282-userImage-1744225798855', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (281, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/9/281-diagramImage-1744225840312', 45, 'SummaryView-L1', 'SummaryView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/9/281-userImage-1744225791834', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (270, 'Наблюдается ограниченная площадь опоры стопы и сниженная подвижность голеностопного сустава могут привести к мышечному дисбалансу в бедрах и тазобедренном суставе. Также наблюдается смещение таза вправо что будет создавать дополнительный мышечный гипертонус вправо ', 'https://storage.googleapis.com/fit_review/review/9/270-diagramImage-1744227363936', null, 'BackView-R3', 'BackView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/9/270-userImage-1744227562747', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (321, 'Стрелка 1. Из-за различной длины рук дельтовидная мышца может быть в гипотонусе, что приводит к перегрузке ротаторов плеча и верхней части трапециевидной мышцы, вызывая дисфункции в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/11/321-diagramImage-1744288520070', null, 'FrontView-L1', 'FrontView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/11/321-userImage-1744288348387', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (298, 'Стрелка 1: Перегрузка верхней части правой трапециевидной мышцы. Может быть связана с слабостью мышц плеча 
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (283, 'Туловище.  Обратиться к массажисту, также найти специалиста кто выполняет висцеральный массаж.  В тренировках уделить внимание на улучшение навыка дыхания под нагрузкой, укрепление мышц разгибателей корпуса и мышц живота. Работать с загрузкой одной стороны и разгрузкой/вытяжением  другой. По формату тренировок-  динамический стретчинг, функциональный тренинг (работа над улучшением контроля движения работа над восстановлением мышечного баланса ) силовой тренинг ', 'https://storage.googleapis.com/fit_review/review/9/283-diagramImage-1744225850420', 50, 'SummaryView-L2', 'SummaryView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/9/283-userImage-1744225803854', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (261, 'Стрелка 9. Ограничение подвижности стопы и голеностопного сустава изменяет работу мышц бедра и таза, что может привести к смещению тазобедренного и коленного суставов. Нагрузки на внутреннюю поверхность бедра увеличиваются, что может вызвать нестабильность коленного сустава.', 'https://storage.googleapis.com/fit_review/review/9/261-diagramImage-1744205926047', null, 'FrontView-L3', 'FrontView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/9/261-userImage-1744206127081', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (262, 'Стрелка 5. Ограничение подвижности стопы и голеностопного сустава изменяет работу мышц бедра и таза, что может привести к смещению тазобедренного и коленного суставов. Нагрузки на внутреннюю поверхность бедра увеличиваются, что может вызвать нестабильность коленного сустава.', 'https://storage.googleapis.com/fit_review/review/9/262-diagramImage-1744205932428', null, 'FrontView-R3', 'FrontView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/9/262-userImage-1744206132229', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (263, 'Стрелка 8. Cтопа и голеностопный сустав.  Внутрення сторона стопы касается пола, это говорит от том что есть дисбаланс в мышцах участвующих за стабилизацию стопы,  движение пальцев стопы, мышц голени. По этой причине, стопа становится менее стабильной, теряет площадь опоры, точки опоры далее изменяется движения  голеностопного сустава. Сгибание и разгибание в голеностопном суставе будет происходить с ограниченностью и дальнейшем создавать дисфункции в верхний регионах - таз, грудной отдел ', 'https://storage.googleapis.com/fit_review/review/9/263-diagramImage-1744205940974', null, 'FrontView-L4', 'FrontView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/9/263-userImage-1744206139106', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (319, 'Стопа. Обратиться  специалисту по стелькам, одновременно. с этим выполнять упражнения на улучшения общего тонуса мышц стопы, ходить босиком чаще, носить обувь с широким носком и равномерно подошвой,  ', 'https://storage.googleapis.com/fit_review/review/10/319-diagramImage-1742828512120', 45, 'SummaryView-L4', 'SummaryView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/10/319-userImage-1742828443560', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (361, 'Стрелка 1. Гипотонус дельтовидной мышцы, возможно из-за фасциального укорочения, триггеров или микротравмы. Руку стабилизируют ротаторы плеча, дельтовидная мышца  и верх трапеции, что со временем может вызвать при дисфункции этих мышц  перегрузку и дисфункции в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/12/361-diagramImage-1746095822444', null, 'BackView-L1', 'BackView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/12/361-userImage-1746095739115', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (306, 'Стрелка 1: Незначительное смещение головы вперед, вероятно, вызвано изменениями в структуре позвонков или отклонением таза от нейтрального положения. Рекомендуется оценить функцию шейных мышц, ответственных за стабилизацию и движение головы.', 'https://storage.googleapis.com/fit_review/review/10/306-diagramImage-1742768607758', null, 'SideView-R1', 'SideView', 'Right View Upper Body', 'https://storage.googleapis.com/fit_review/review/10/306-userImage-1742768550466', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (297, 'Наблюдается мышечный дисбаланс в шейно-плечелопаточной области, особенно справа. Нестабильность мышц плеча и лопатки может привести к нарушению функции трапециевидной мышцы, влияя на стабилизацию и движение шейного отдела.', 'https://storage.googleapis.com/fit_review/review/10/297-diagramImage-1742768398224', null, 'BackView-L1', 'BackView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/10/297-userImage-1742768319572', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (313, 'Шейный регион. Обратиться к массажисту, кинезиологу, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело, глазо-двигательную гимнастку, работать над улучшением работы мышц кора.  ', 'https://storage.googleapis.com/fit_review/review/10/313-diagramImage-1742828473639', 45, 'SummaryView-L1', 'SummaryView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/10/313-userImage-1742828396777', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (310, 'Стрелка 4:Переразгибание коленного сустава с выдвижением надколенника вперёд может быть врождённым или приобретённым. В обоих случаях существует риск повреждения передней крестообразной связки и перегрузки связочного аппарата колена. Рекомендуется контролировать положение колена при стоянии и разгибании, а также укреплять мышцы задней группы бедра для стабилизации сустава.', 'https://storage.googleapis.com/fit_review/review/10/310-diagramImage-1742768632841', null, 'SideView-R3', 'SideView', 'Right View Hips', 'https://storage.googleapis.com/fit_review/review/10/310-userImage-1742768573954', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (309, 'Стрелка 5: Переразгибание коленного сустава с выдвижением надколенника вперёд может быть врождённым или приобретённым. В обоих случаях существует риск повреждения передней крестообразной связки и перегрузки связочного аппарата колена. Рекомендуется контролировать положение колена при стоянии и разгибании, а также укреплять мышцы задней группы бедра для стабилизации сустава.', 'https://storage.googleapis.com/fit_review/review/10/309-diagramImage-1742768625965', null, 'SideView-L3', 'SideView', 'Left View Hips', 'https://storage.googleapis.com/fit_review/review/10/309-userImage-1742768568081', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (316, 'Туловище. Ранее описанные рекомендации вы можете изучить еще раз слева. Важно обратить внимание.  Это ядро человека где проходят все важные процессы для поддержания жизнедеятельности в особенности структура тела ', 'https://storage.googleapis.com/fit_review/review/10/316-diagramImage-1742828490734', 16, 'SummaryView-R2', 'SummaryView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/10/316-userImage-1742828426352', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (315, 'Туловище. Сделать узи, визит к гастроэнтерологу, получит консультацию и рекомендацию по питанию, составлении плана исходя из целей, дыхательная гимнастика, функциональная гимнастика работа с позвонок плечелопаточным регионом, укрепление мышц кора ', 'https://storage.googleapis.com/fit_review/review/10/315-diagramImage-1742828484964', 50, 'SummaryView-L2', 'SummaryView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/10/315-userImage-1742828418468', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (317, 'Тазобедренный сустав.  Разгрузить мышцы приводящие бедро, восстановить тонус работы мышц бедра, работать со стопой. Обратиться к массажисту, кинезиологу для  разгрузки мышечного напряжения, протестировать мышечный ресурс. применить утреннюю гимнастику на улучшение мобильности таза и бедра, функциональный тренинг с свободным весом, силовой тренинг , подвижные виды игр ', 'https://storage.googleapis.com/fit_review/review/10/317-diagramImage-1742828498792', 65, 'SummaryView-L3', 'SummaryView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/10/317-userImage-1742828432901', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (326, 'Стрелка 4. Коленная чашечка смещена от нейтрального положения. Причины — нарушение шага, перенос веса, неправильное распределение опоры, смещение костей голеностопа и снижение его функции. Это ведет к  дисбалансу мышц бедра и компенсаторным изменениям по телу.', 'https://storage.googleapis.com/fit_review/review/11/326-diagramImage-1744288548327', null, 'FrontView-R3', 'FrontView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/11/326-userImage-1744288390802', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (334, 'Стрелка 6. Ось костей голени и бедра направлены по-разному, что влияет на распределение нагрузки на колено, перегружает связки и вызывает мышечный дисбаланс в голени, бедре и тазу. Возможная причина — нарушение работы стопы и голеностопного сустава.', 'https://storage.googleapis.com/fit_review/review/11/334-diagramImage-1744289907276', null, 'BackView-R3', 'BackView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/11/334-userImage-1744289427588', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (322, 'Наблюдается дисбаланс мышц в шейном и плечево-лопаточном отделах, особенно с правой стороны. Эта нестабильность может приводить к нарушению работы мышц шеи и плеча.', 'https://storage.googleapis.com/fit_review/review/11/322-diagramImage-1744288526042', null, 'FrontView-R1', 'FrontView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/11/322-userImage-1744288251462', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (307, 'Стрелка 2: Рука повернута к корпусу, что может быть связано с ранее описанными причинами (см. лицевой и задний виды). Вид сбоку дополнительно демонстрирует близость руки к телу.
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (291, 'Стрелка 3: Правый локоть выше левого, рука сильнее прижата к корпусу. Возможные причины: слабость дельтовидной мышцы и перегрузка верхней части трапециевидной мышцы, что может приводить к дисбалансу ротаторов плеча и мышц, окружающих лопатку. Это влияет на положение предплечья и ладони, которые должны быть направлены друг к другу.
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (299, 'Несмотря на более правильное положение левой руки, небольшое отдаление локтя от корпуса может свидетельствовать о дисбалансе мышц плеча и лопаточной области. Такие нарушения часто возникают из-за неравномерной нагрузки или травм, что приводит к болям и снижению подвижности в плечевом суставе. ', 'https://storage.googleapis.com/fit_review/review/10/299-diagramImage-1742768411775', null, 'BackView-L2', 'BackView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/10/299-userImage-1742768334378', 10);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (258, 'Стрелка 1. Ключица направлена вниз по дуге, это будет влиять на форму, объемность вдоха в грудной клетки, выпячивание лопаток( торчащие сзади ) , уплощение грудной клетки. Также вероятно защемление нервных окончаний и онемение рук при держании над головой. ', 'https://storage.googleapis.com/fit_review/review/9/258-diagramImage-1744205908934', null, 'FrontView-R1', 'FrontView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/9/258-userImage-1744206111027', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (276, 'Стрелка 2: Кифоз грудного отдела (избыточная выпуклость позвоночника назад) сопровождается опущением рёбер и может быть вызван смещением таза вперёд и нарушением распределения веса. Это приводит к слабости мышц-разгибателей позвоночника, мышц живота, дисбалансу межрёберных мышц, диафрагмы и мышц, окружающих лопатку. ￼
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (274, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце.и других мышц разгибателей корпуса ', 'https://storage.googleapis.com/fit_review/review/9/274-diagramImage-1743507634427', null, 'SideView-R1', 'SideView', 'Right View Upper Body', 'https://storage.googleapis.com/fit_review/review/9/274-userImage-1743507561653', 9);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (368, 'С правой стороны стопа выглядит немного лучше как и ахилл, но все же наблюдается, что стопа больше опирается на внутренний свод чем на внешний. ', 'https://storage.googleapis.com/fit_review/review/12/368-diagramImage-1746095868502', null, 'BackView-R4', 'BackView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/12/368-userImage-1746095764005', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (328, 'Стрелка 5. Стопа выглядит визуально хорошо: присутствует арка, есть пространство между пальцами. Однако форма голени немного изогнута, коленная чашечка смещена внутрь. Это указывает на возможный мышечный дисбаланс голени и бедра и функциональные нарушения при шаге или движении — сустав и мышцы могут работать нестабильно.', 'https://storage.googleapis.com/fit_review/review/11/328-diagramImage-1744288555763', null, 'FrontView-R4', 'FrontView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/11/328-userImage-1744288402355', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (325, 'Стрелка 4. Коленная чашечка смещена от нейтрального положения. Причины — нарушение шага, перенос веса, неправильное распределение опоры, смещение костей голеностопа и снижение его функции. Это ведет к  дисбалансу мышц бедра и компенсаторным изменениям по телу.', 'https://storage.googleapis.com/fit_review/review/11/325-diagramImage-1744288543616', null, 'FrontView-L3', 'FrontView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/11/325-userImage-1744288387366', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (323, 'Стрелка 2. С правой стороны видно укорочение тканей, корпус асимметричен. Возможно связано с привычной позой стоя или сидя где корпус постоянно наклонен вправо , ношение тяжестей на одну сторону. Есть дисбаланс в косых мышцах живота, межрёберных мышцах, диафрагме и разгибателях спины.', 'https://storage.googleapis.com/fit_review/review/11/323-diagramImage-1744288532549', null, 'FrontView-L2', 'FrontView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/11/323-userImage-1744288356894', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (330, 'Стрелка 1. Гипотонус дельтовидной мышцы, возможно из-за фасциального укорочения, триггеров или микротравмы. Руку стабилизируют ротаторы плеча, дельтовидная мышца  и верх трапеции, что со временем может вызвать при дисфункции этих мышц  перегрузку и дисфункции в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/11/330-diagramImage-1744289880737', null, 'BackView-R1', 'BackView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/11/330-userImage-1744289402772', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (324, 'Стрелка 3. Наблюдается вытяжение тканей, левая сторона выглядит более вытянутой чем правая. Возможно связано с привычной позой стоя или сидя где корпус постоянно наклонен вправо, ношение тяжестей на одну сторону. Есть дисбаланс в косых мышцах живота, межрёберных мышцах, диафрагме и разгибателях спины.', 'https://storage.googleapis.com/fit_review/review/11/324-diagramImage-1744288536862', null, 'FrontView-R2', 'FrontView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/11/324-userImage-1744288380430', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (341, 'Положение таза в норме, но есть вопросы к работе ягодичных мышц. Видна слабость разгибателей спины, а ягодичные фасциально связаны с ними, что может указывать на общий мышечный дисбаланс.', 'https://storage.googleapis.com/fit_review/review/11/341-diagramImage-1744290499222', null, 'SideView-L3', 'SideView', 'Left View Hips', 'https://storage.googleapis.com/fit_review/review/11/341-userImage-1744290903150', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (331, 'Стрелка 3. Наблюдается сильный пробор вдоль позвонка. Мышцы разгибали позвонка в гипотонусе, не могут удерживать позвонок в сгибании, разгибании его стабилизации, это будет влиять на форму осанки, работы мышц кора, всей мышечной задней линии тела', 'https://storage.googleapis.com/fit_review/review/11/331-diagramImage-1744289887248', null, 'BackView-L2', 'BackView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/11/331-userImage-1744289410401', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (344, 'Стрелка 5 Вид стопы и голени с стороны неплохой, как и ранее упоминалось имеется арка стопы, пространство между пальцев. ', 'https://storage.googleapis.com/fit_review/review/11/344-diagramImage-1744290509786', null, 'SideView-R4', 'SideView', 'Right View Feet', 'https://storage.googleapis.com/fit_review/review/11/344-userImage-1744290917058', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (329, 'Наблюдается мышечный дисбаланс в шейно-плечелопаточной области, особенно справа. Нестабильность мышц плеча и лопатки нарушает работу трапециевидной мышцы, что влияет на стабилизацию и движение шейного отдела.', 'https://storage.googleapis.com/fit_review/review/11/329-diagramImage-1744289873008', null, 'BackView-L1', 'BackView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/11/329-userImage-1744289390724', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (345, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/11/345-diagramImage-1744288563880', 55, 'SummaryView-L1', 'SummaryView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/11/345-userImage-1744288414235', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (354, 'Стрелка 1. Из-за различной длины рук дельтовидная мышца может быть в гипотонусе, что приводит к перегрузке ротаторов плеча и верхней части трапециевидной мышцы, вызывая дисфункции в шейном отделе.', 'https://storage.googleapis.com/fit_review/review/12/354-diagramImage-1746095596719', null, 'FrontView-R1', 'FrontView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/12/354-userImage-1746095304606', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (327, 'Стрелка 5. Стопа выглядит визуально хорошо: присутствует арка, есть пространство между пальцами. Однако форма голени немного изогнута, коленная чашечка смещена внутрь. Это указывает на возможный мышечный дисбаланс голени и бедра и функциональные нарушения при шаге или движении — сустав и мышцы могут работать нестабильно.', 'https://storage.googleapis.com/fit_review/review/11/327-diagramImage-1744288552577', null, 'FrontView-L4', 'FrontView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/11/327-userImage-1744288399554', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (365, 'Стрелка 3 Ось костей голени и бедра направлены по-разному, что влияет на распределение нагрузки на колено, перегружает связки и вызывает мышечный дисбаланс в голени, бедре и тазу. Возможная причина — нарушение работы стопы и голеностопного сустава.', 'https://storage.googleapis.com/fit_review/review/12/365-diagramImage-1746095845026', null, 'BackView-L3', 'BackView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/12/365-userImage-1746095757276', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (379, 'Туловище. Рекомендуется массаж, включая висцеральный. В тренировках — работа над дыханием под нагрузкой, укрепление мышц живота и разгибателей корпуса. Добавить одностороннюю нагрузку с вытяжением противоположной стороны. Форматы: динамический стретчинг, функциональный и силовой тренинг.', 'https://storage.googleapis.com/fit_review/review/12/379-diagramImage-1746095500180', 60, 'SummaryView-L2', 'SummaryView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/12/379-userImage-1746175858564', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (353, 'Наблюдается дисбаланс мышц в шейном и плечево-лопаточном отделах, особенно с левой стороны. Эта нестабильность может приводить к нарушению работы мышц шеи и плеча.', 'https://storage.googleapis.com/fit_review/review/12/353-diagramImage-1746095464150', null, 'FrontView-L1', 'FrontView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/12/353-userImage-1746095299748', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (355, 'Стрелка 2. С правой стороны видно укорочение тканей, корпус асимметричен. Возможно связано с привычной позой стоя или сидя где корпус постоянно наклонен вправо , ношение тяжестей на одну сторону. Есть дисбаланс в косых мышцах живота, межрёберных мышцах, диафрагме и разгибателях спины.', 'https://storage.googleapis.com/fit_review/review/12/355-diagramImage-1746095468090', null, 'FrontView-L2', 'FrontView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/12/355-userImage-1746172973473', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (336, 'Стрелка 5. Ахилл справа немного втянут внутрь, что уже создаёт дисбаланс мышц голени. При шаге опора, вероятно, смещена на внутреннюю сторону стопы, что меняет перенос веса и распределение нагрузки. Это ведёт к дисбалансу мышц бедра, таза и компенсаторным изменениям по всему телу.', 'https://storage.googleapis.com/fit_review/review/11/336-diagramImage-1744289916251', null, 'BackView-R4', 'BackView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/11/336-userImage-1744289437665', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (342, 'Положение таза в норме, но есть вопросы к работе ягодичных мышц. Видна слабость разгибателей спины, а ягодичные фасциально связаны с ними, что может указывать на общий мышечный дисбаланс.', 'https://storage.googleapis.com/fit_review/review/11/342-diagramImage-1744290503054', null, 'SideView-R3', 'SideView', 'Right View Hips', 'https://storage.googleapis.com/fit_review/review/11/342-userImage-1744290906569', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (347, 'Туловище. Рекомендуется массаж, включая висцеральный. В тренировках — работа над дыханием под нагрузкой, укрепление мышц живота и разгибателей корпуса. Добавить одностороннюю нагрузку с вытяжением противоположной стороны. Форматы: динамический стретчинг, функциональный и силовой тренинг.', 'https://storage.googleapis.com/fit_review/review/11/347-diagramImage-1744288573106', 50, 'SummaryView-L2', 'SummaryView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/11/347-userImage-1744288424687', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (348, 'Туловище. Рекомендуется массаж, включая висцеральный. В тренировках — работа над дыханием под нагрузкой, укрепление мышц живота и разгибателей корпуса. Добавить одностороннюю нагрузку с вытяжением противоположной стороны. Форматы: динамический стретчинг, функциональный и силовой тренинг.', 'https://storage.googleapis.com/fit_review/review/11/348-diagramImage-1744288576038', 50, 'SummaryView-R2', 'SummaryView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/11/348-userImage-1744288429934', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (351, 'Стопа. Выполнять упражнения на улучшение общего тонуса мышц стопы, приоритет тренировок на стабилизацию стопы и улучшение её площади опоры. Ходить босиком чаще, носить обувь с широким носком и равномерной подошвой. ', 'https://storage.googleapis.com/fit_review/review/11/351-diagramImage-1744288588296', 60, 'SummaryView-L4', 'SummaryView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/11/351-userImage-1744288445490', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (357, 'Стрелка 4. Коленная чашечка смещена в сторону  от нейтрального положения. Причины — нарушение шага, перенос веса, неправильное распределение опоры, смещение костей голеностопного   сустава и снижение его функции. Это ведет к  дисбалансу мышц бедра и компенсаторным изменениям по телу.', 'https://storage.googleapis.com/fit_review/review/12/357-diagramImage-1746095476393', null, 'FrontView-L3', 'FrontView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/12/357-userImage-1746172982949', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (358, 'Стрелка 4. Коленная чашечка смещена в сторону  от нейтрального положения. Причины — нарушение шага, перенос веса, неправильное распределение опоры, смещение костей голеностопного сустава и снижение его функции. Это ведет к  дисбалансу мышц бедра и компенсаторным изменениям по телу.', 'https://storage.googleapis.com/fit_review/review/12/358-diagramImage-1746095613942', null, 'FrontView-R3', 'FrontView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/12/358-userImage-1746172986427', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (366, 'Стрелка 3 Ось костей голени и бедра направлены по-разному, что влияет на распределение нагрузки на колено, перегружает связки и вызывает мышечный дисбаланс в голени, бедре и тазу. Возможная причина — нарушение работы стопы и голеностопного сустава.', 'https://storage.googleapis.com/fit_review/review/12/366-diagramImage-1746095848597', null, 'BackView-R3', 'BackView', 'Hips Left', 'https://storage.googleapis.com/fit_review/review/12/366-userImage-1746095760516', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (362, 'Наблюдается мышечный дисбаланс в шейно-плечелопаточной области, особенно справа. Нестабильность мышц плеча и лопатки нарушает работу трапециевидной мышцы, что влияет на стабилизацию и движение шейного отдела.', 'https://storage.googleapis.com/fit_review/review/12/362-diagramImage-1746095826417', null, 'BackView-R1', 'BackView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/12/362-userImage-1746095743352', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (339, 'Стрелка 2. Кифоз грудного отдела. Наблюдается округленная форма спины. Вероятен гипотонус разгибателей позвоночника и корпуса. Возможно присутствует мышечный дисбаланс, особенно в зоне кора. Стрелка 3. Форма живота указывает на слабую работу мышц пресса и диафрагмы. Дыхание, вероятно, поверхностное — в верхней части грудной клетки, без вовлечения живота. Это снижает эффективность дыхательного процесса и стабилизации корпуса.  Стрелка 4. Положение таза в норме, но есть вопросы к работе ягодичных мышц. Видна слабость разгибателей спины, а ягодичные фасциально связаны с ними, что может указывать на общий мышечный дисбаланс.', 'https://storage.googleapis.com/fit_review/review/11/339-diagramImage-1744290491308', null, 'SideView-L2', 'SideView', 'Left View Core', 'https://storage.googleapis.com/fit_review/review/11/339-userImage-1744290895020', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (370, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце и других мышц разгибателей корпуса .', 'https://storage.googleapis.com/fit_review/review/12/370-diagramImage-1746096080714', null, 'SideView-R1', 'SideView', 'Right View Upper Body', 'https://storage.googleapis.com/fit_review/review/12/370-userImage-1746095936796', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (384, 'Стопа. Выполнять упражнения на улучшение общего тонуса мышц стопы, приоритет тренировок на стабилизацию стопы и улучшение её площади опоры. Ходить босиком чаще, носить обувь с широким носком и равномерной подошвой. ', 'https://storage.googleapis.com/fit_review/review/12/384-diagramImage-1746095659086', 60, 'SummaryView-R4', 'SummaryView', 'Feet Left', 'https://storage.googleapis.com/fit_review/review/12/384-userImage-1746095406751', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (340, 'Стрелка 2. Кифоз грудного отдела. Наблюдается округленная форма спины. Вероятен гипотонус разгибателей позвоночника и корпуса. Возможно присутствует мышечный дисбаланс, особенно в зоне кора. Стрелка 3. Форма живота указывает на слабую работу мышц пресса и диафрагмы. Дыхание, вероятно, поверхностное — в верхней части грудной клетки, без вовлечения живота. Это снижает эффективность дыхательного процесса и стабилизации корпуса.  Стрелка 4. Положение таза в норме, но есть вопросы к работе ягодичных мышц. Видна слабость разгибателей спины, а ягодичные фасциально связаны с ними, что может указывать на общий мышечный дисбаланс.', 'https://storage.googleapis.com/fit_review/review/11/340-diagramImage-1744290494882', null, 'SideView-R2', 'SideView', 'Right View Core', 'https://storage.googleapis.com/fit_review/review/11/340-userImage-1744290898354', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (380, 'Туловище. Рекомендуется массаж, включая висцеральный. В тренировках — работа над дыханием под нагрузкой, укрепление мышц живота и разгибателей корпуса. Добавить одностороннюю нагрузку с вытяжением противоположной стороны. Форматы: динамический стретчинг, функциональный и силовой тренинг.', 'https://storage.googleapis.com/fit_review/review/12/380-diagramImage-1746095645540', 60, 'SummaryView-R2', 'SummaryView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/12/380-userImage-1746095377752', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (381, 'Бедро. Восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/12/381-diagramImage-1746095506607', 60, 'SummaryView-L3', 'SummaryView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/12/381-userImage-1746175848131', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (349, 'Бедро. Восстановить мышечный тонус бедра, первоначально работая над  стопой, восстановить опору, площадь опоры.  улучшить мобильность таза. Помогут массаж, утренняя гимнастика, функциональный и силовой тренинг, активные игры.', 'https://storage.googleapis.com/fit_review/review/11/349-diagramImage-1744288579703', 65, 'SummaryView-L3', 'SummaryView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/11/349-userImage-1744288434973', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (333, 'Стрелка 6. Ось костей голени и бедра направлены по-разному, что влияет на распределение нагрузки на колено, перегружает связки и вызывает мышечный дисбаланс в голени, бедре и тазу. Возможная причина — нарушение работы стопы и голеностопного сустава.', 'https://storage.googleapis.com/fit_review/review/11/333-diagramImage-1744289903152', null, 'BackView-L3', 'BackView', 'Hips Right', 'https://storage.googleapis.com/fit_review/review/11/333-userImage-1744289423294', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (332, 'Стрелка 2. Правая лопатка выше и дальше от позвоночника. Есть слабость разгибателей корпуса и гипотонус мышц, стабилизирующих и мобилизующих лопатку. Это снижает контроль и подвижность лопатки, придает нестабильную работу грудного региона, дисбаланс мышц кора, коррекцией осанки. Стрелка 3 Наблюдается сильный пробор вдоль позвонка. Мышцы разгибали позвонка в гипотонусе, не могут удерживать позвонок в сгибании, разгибании его стабилизации, это будет влиять на форму осанки, работы мышц кора, всей мышечной задней линии тела Стрелка 4. Линия талии справа немного выше чем слева, возможно укорочение тканей,', 'https://storage.googleapis.com/fit_review/review/11/332-diagramImage-1744289892755', null, 'BackView-R2', 'BackView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/11/332-userImage-1744289416052', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (337, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце и других мышц разгибателей корпуса .', 'https://storage.googleapis.com/fit_review/review/11/337-diagramImage-1744290465702', null, 'SideView-L1', 'SideView', 'Left View Upper Body', 'https://storage.googleapis.com/fit_review/review/11/337-userImage-1744290885931', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (335, 'Стрелка 5. Предполагается что левая стопа слегка наклонена внутрь, внешняя часть приподнята. Это может указывать на мышечный дисбаланс в формировании и стабилизации свода стопы. При шаге опора, вероятно, смещается внутрь, что нарушает перенос веса и распределение нагрузки.', 'https://storage.googleapis.com/fit_review/review/11/335-diagramImage-1744289913639', null, 'BackView-L4', 'BackView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/11/335-userImage-1744289433478', 11);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (275, 'Стрелка 2: Смещение грудного отдела позвоночника назад и сжатость рёбер могут быть вызваны смещением таза вперёд и нарушением распределения веса. Это приводит к гипотонусу мышц-разгибателей туловища, которые не способны поддерживать позвоночник и удерживать грудную клетку в нейтральном положении.
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (363, 'Стрелка 2. Асимметрия корпуса и таза: левая сторона выше. Спереди — противоположная асимметрия, что может указывать на фасциальное укорочение спереди и смещение тазовой кости сзади, с триггерами и укорочением разгибателей позвоночника, это будет сказываться на  слабость разгибателей спины и ягодичных , а ягодичные фасциально связаны с ними, что может указывать на общий мышечный дисбаланс.', 'https://storage.googleapis.com/fit_review/review/12/363-diagramImage-1746095833629', null, 'BackView-L2', 'BackView', 'Core Right', 'https://storage.googleapis.com/fit_review/review/12/363-userImage-1746173877935', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (369, 'Стрелка 1: Смещение головы вперёд, вероятно, вызвано сдвигом таза вперёд и грудной клетки назад, а также опорой на пятки. Это приводит к неправильному распределению веса и мышечному дисбалансу в шейном отделе, особенно в трапециевидной мышце и других мышц разгибателей корпуса .', 'https://storage.googleapis.com/fit_review/review/12/369-diagramImage-1746096073895', null, 'SideView-L1', 'SideView', 'Left View Upper Body', 'https://storage.googleapis.com/fit_review/review/12/369-userImage-1746095933689', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (367, 'Стрелка 5. Наблюдается, как  ахиллово сухожилие и сама  стопа слегка наклонена внутрь . Это может указывать на мышечный дисбаланс в формировании и стабилизации свода стопы и мышц голени. При шаге опора, вероятно, смещается внутрь, что нарушает перенос веса и распределение нагрузки.', 'https://storage.googleapis.com/fit_review/review/12/367-diagramImage-1746095865636', null, 'BackView-L4', 'BackView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/12/367-userImage-1746175260513', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (375, 'Стрелка 4 Вид стопы и голени с стороны неплохой, как и ранее упоминалось имеется арка стопы, пространство между пальцев. Но есть вопрос к функционалу мизинца так как сильно выделяется в сторону, если есть дисфункция, то это будет сказываться на работе всей структуры  стопы ', 'https://storage.googleapis.com/fit_review/review/12/375-diagramImage-1746096101685', null, 'SideView-L4', 'SideView', 'Left View Feet', 'https://storage.googleapis.com/fit_review/review/12/375-userImage-1746095963289', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (372, 'Стрелка 2. Кифоз грудного отдела. Наблюдается округленная форма спины. Вероятен гипотонус разгибателей позвоночника и корпуса. Возможно присутствует мышечный дисбаланс, особенно в зоне кора. Форма живота указывает на слабую работу мышц пресса и диафрагмы. Дыхание, вероятно, поверхностное — в верхней части грудной клетки, без вовлечения живота. Это снижает эффективность дыхательного процесса и стабилизации корпуса.', 'https://storage.googleapis.com/fit_review/review/12/372-diagramImage-1746096087197', null, 'SideView-R2', 'SideView', 'Right View Core', 'https://storage.googleapis.com/fit_review/review/12/372-userImage-1746095945793', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (371, 'Стрелка 2. Кифоз грудного отдела. Наблюдается округленная форма спины. Вероятен гипотонус разгибателей позвоночника и корпуса. Возможно присутствует мышечный дисбаланс, особенно в зоне кора. Форма живота указывает на слабую работу мышц пресса и диафрагмы. Дыхание, вероятно, поверхностное — в верхней части грудной клетки, без вовлечения живота. Это снижает эффективность дыхательного процесса и стабилизации корпуса.', 'https://storage.googleapis.com/fit_review/review/12/371-diagramImage-1746096084057', null, 'SideView-L2', 'SideView', 'Left View Core', 'https://storage.googleapis.com/fit_review/review/12/371-userImage-1746095941145', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (359, 'Стрелка 6 Стрелка 5  Стопа выглядит визуально хорошо: присутствует арка, есть пространство между пальцами. Однако форма голени немного развернута наружу вместе с коленной  чашечкой. Это указывает на возможный мышечный дисбаланс голени и бедра и функциональные нарушения при шаге или движении — сустав и мышцы могут работать нестабильно.', 'https://storage.googleapis.com/fit_review/review/12/359-diagramImage-1746095483578', null, 'FrontView-L4', 'FrontView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/12/359-userImage-1746172990770', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (373, 'Стрелка 3: Смещение таза вперёд может быть вызвано слабостью задней группы мышц: ягодичных, задней поверхности бедра, икроножных и мышц стопы. Основные причины включают сидячий образ жизни, неправильное распределение веса и изменения в функционировании нижних конечностей.', 'https://storage.googleapis.com/fit_review/review/12/373-diagramImage-1746096091941', null, 'SideView-L3', 'SideView', 'Left View Hips', 'https://storage.googleapis.com/fit_review/review/12/373-userImage-1746095953616', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (374, 'Стрелка 3: Смещение таза вперёд может быть вызвано слабостью задней группы мышц: ягодичных, задней поверхности бедра, икроножных и мышц стопы. Основные причины включают сидячий образ жизни, неправильное распределение веса и изменения в функционировании нижних конечностей.', 'https://storage.googleapis.com/fit_review/review/12/374-diagramImage-1746096095070', null, 'SideView-R3', 'SideView', 'Right View Hips', 'https://storage.googleapis.com/fit_review/review/12/374-userImage-1746095956996', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (376, 'Вид стопы и голени с стороны неплохой, как и ранее упоминалось имеется арка стопы, пространство между пальцев. ', 'https://storage.googleapis.com/fit_review/review/12/376-diagramImage-1746096104756', null, 'SideView-R4', 'SideView', 'Right View Feet', 'https://storage.googleapis.com/fit_review/review/12/376-userImage-1746095966205', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (377, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/12/377-diagramImage-1746095493584', 60, 'SummaryView-L1', 'SummaryView', 'Upper Body Right', 'https://storage.googleapis.com/fit_review/review/12/377-userImage-1746095366370', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (378, 'Шейный регион. Обратиться к массажисту, для разгрузки мышц шейного региона плечевого региона  и восстановлени симметрии. Добавить утреннюю гимнастику на все тело. В тренировках держать приоритет на укрепление мышц разгибателей все задней мышечной линии ( мышцы разгибатели от затылка до стопы ) и укрепить мышцы живота. ', 'https://storage.googleapis.com/fit_review/review/12/378-diagramImage-1746095638479', 60, 'SummaryView-R1', 'SummaryView', 'Upper Body Left', 'https://storage.googleapis.com/fit_review/review/12/378-userImage-1746175863416', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (383, 'Стопа. Выполнять упражнения на улучшение общего тонуса мышц стопы, приоритет тренировок на стабилизацию стопы и улучшение её площади опоры. Ходить босиком чаще, носить обувь с широким носком и равномерной подошвой. ', 'https://storage.googleapis.com/fit_review/review/12/383-diagramImage-1746095510625', 60, 'SummaryView-L4', 'SummaryView', 'Feet Right', 'https://storage.googleapis.com/fit_review/review/12/383-userImage-1746175838312', 12);
INSERT INTO public.body_segment (id, description, diagram_image, estimation, name, segment_group, title, user_image, review_id) VALUES (356, 'Стрелка 3. Наблюдается вытяжение тканей, левая сторона выглядит слегка вытянутой чем правая, определяется подгрудными складками . Возможно связано с привычной позой стоя или сидя где корпус постоянно наклонен вправо, ношение тяжестей на одну сторону. Есть дисбаланс в косых мышцах живота, межрёберных мышцах, диафрагме и разгибателях спины.', 'https://storage.googleapis.com/fit_review/review/12/356-diagramImage-1746095604571', null, 'FrontView-R2', 'FrontView', 'Core Left', 'https://storage.googleapis.com/fit_review/review/12/356-userImage-1746172791841', 12);
